@using System.Threading
@inject IProductService ProductService
@implements IDisposable

<div class="product-search">
    <input type="text"
           placeholder="Search products…"
           @oninput="OnSearchInput"
           value="@_query" />

    @if (_loading)
    {
        <div class="product-search-status">Searching…</div>
    }
    else if (_error is not null)
    {
        <div class="product-search-status product-search-error">
            Something went wrong. <button @onclick="RetrySearch">Retry</button>
        </div>
    }
    else if (_searched && _results.Count == 0)
    {
        <div class="product-search-status">No products found.</div>
    }

    @if (_results.Count > 0)
    {
        <div class="product-search-results">
            @foreach (var product in _results)
            {
                <div class="product-card" @onclick="() => SelectProduct(product)">
                    <img src="@product.ImageUrl" alt="@product.Name" />
                    <div class="product-card-body">
                        <h4>@product.Name</h4>
                        <p>@product.Price.ToString("C")</p>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private string _query = string.Empty;
    private List<Product> _results = new();
    private bool _loading;
    private bool _searched;
    private string? _error;

    private Timer? _debounceTimer;
    private CancellationTokenSource? _searchCts;

    private void OnSearchInput(ChangeEventArgs e)
    {
        _query = e.Value?.ToString() ?? string.Empty;
        _debounceTimer?.Dispose();

        if (string.IsNullOrWhiteSpace(_query))
        {
            CancelInflightSearch();
            _results = new();
            _searched = false;
            _loading = false;
            _error = null;
            return;
        }

        _debounceTimer = new Timer(_ => InvokeAsync(ExecuteSearch), null, 300, Timeout.Infinite);
    }

    private async Task ExecuteSearch()
    {
        CancelInflightSearch();

        var cts = new CancellationTokenSource();
        _searchCts = cts;

        _loading = true;
        _error = null;
        StateHasChanged();

        try
        {
            var results = await ProductService.SearchAsync(_query, cts.Token);

            // Another search may have started while we were awaiting — discard stale results.
            if (cts.Token.IsCancellationRequested)
                return;

            _results = results;
            _searched = true;
        }
        catch (OperationCanceledException)
        {
            // Search was intentionally cancelled; do nothing.
            return;
        }
        catch (Exception)
        {
            if (cts.Token.IsCancellationRequested)
                return;

            _results = new();
            _error = "failed";
        }
        finally
        {
            // Only clear the loading flag if this is still the active search.
            if (_searchCts == cts)
                _loading = false;
        }

        StateHasChanged();
    }

    private void RetrySearch() => _ = ExecuteSearch();

    private async Task SelectProduct(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private void CancelInflightSearch()
    {
        _searchCts?.Cancel();
        _searchCts?.Dispose();
        _searchCts = null;
    }

    public void Dispose()
    {
        _debounceTimer?.Dispose();
        CancelInflightSearch();
    }
}

